import{_ as t,o as a,h as r,a2 as s}from"./chunks/framework.Ciawx864.js";const h=JSON.parse('{"title":"@ui5/project/build/ProjectBuilder","description":"","frontmatter":{"prev":false,"next":false},"headers":[],"relativePath":"api/@ui5_project_build_ProjectBuilder.md","filePath":"api/@ui5_project_build_ProjectBuilder.md"}'),d={name:"api/@ui5_project_build_ProjectBuilder.md"};function o(l,e,i,c,n,p){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="ui5-project-build-projectbuilder" tabindex="-1">@ui5/project/build/ProjectBuilder <a class="header-anchor" href="#ui5-project-build-projectbuilder" aria-label="Permalink to &quot;@ui5/project/build/ProjectBuilder&quot;">​</a></h1><h2 id="ui5-project-build-projectbuilder-1" tabindex="-1">@ui5/project/build/ProjectBuilder <a class="header-anchor" href="#ui5-project-build-projectbuilder-1" aria-label="Permalink to &quot;@ui5/project/build/ProjectBuilder&quot;">​</a></h2><h4 id="new-ui5-project-build-projectbuilder-parameters" tabindex="-1"><div class="jsdoc-object" id="@ui5/project/build/ProjectBuilder"><span class="type-signature"></span>new @ui5/project/build/ProjectBuilder<span class="signature">(parameters)</span><span class="type-signature"></span></div> <a class="header-anchor" href="#new-ui5-project-build-projectbuilder-parameters" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;@ui5/project/build/ProjectBuilder&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;&lt;/span&gt;new @ui5/project/build/ProjectBuilder&lt;span class=&quot;signature&quot;&gt;(parameters)&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt;&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Executes a project build, including all necessary or requested dependencies</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L15" target="_blank" rel="noopener noreferrer">line 15</a></p><h5 id="parameters" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>parameters</code></td><td>object</td><td><br><em>Properties:</em><table class="props"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>graph</code></td><td class="type"><a href="@ui5_project_graph_ProjectGraph">@ui5/project/graph/ProjectGraph</a></td><td class="attributes"></td><td class="description last">Project graph</td></tr><tr><td class="name"><code>buildConfig</code></td><td class="type"><a href="@ui5_project_build_ProjectBuilder#~BuildConfiguration">@ui5/project/build/ProjectBuilder~BuildConfiguration</a></td><td class="attributes">optional</td><td class="description last">Build configuration</td></tr><tr><td class="name"><code>taskRepository</code></td><td class="type">@ui5/builder/tasks/taskRepository</td><td class="attributes"></td><td class="description last">Task Repository module to use</td></tr><tr><td class="name"><code>ui5DataDir</code></td><td class="type">string</td><td class="attributes">optional</td><td class="description last">Explicit UI5 data directory to use for the build cache, overriding the<br> <code>UI5_DATA_DIR</code> environment variable, the UI5 configuration file,<br> and the default of <code>~/.ui5</code>.</td></tr></tbody></table></td></tr></tbody></table><h3 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h3><h4 id="async-build-parameters-projectbuiltcallbackopt-rarr-promise-lt-array-lt-string" tabindex="-1"><div class="jsdoc-object" id="build"><span class="type-signature">(async) </span>build<span class="signature">(parameters, projectBuiltCallback<span class="signature-attributes">opt</span>)</span><span class="type-signature"> → {Promise&lt;Array&lt;string&gt;&gt;}</span></div> <a class="header-anchor" href="#async-build-parameters-projectbuiltcallbackopt-rarr-promise-lt-array-lt-string" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;build&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;(async) &lt;/span&gt;build&lt;span class=&quot;signature&quot;&gt;(parameters, projectBuiltCallback&lt;span class=&quot;signature-attributes&quot;&gt;opt&lt;/span&gt;)&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt; &amp;rarr; {Promise&amp;lt;Array&amp;lt;string&gt;&gt;}&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Build projects without writing to a target directory.</p><p>Intended for long-running consumers (such as the BuildServer) that access build results through readers rather than the file system. Multiple sequential calls are supported and reuse the same build cache.</p><p>The caller is responsible for releasing the underlying build cache database by invoking #closeCacheManager once the builder is no longer needed. Failing to do so leaks the SQLite connection and its memory mapping, which on Windows also blocks deletion of the cache directory by subsequent processes.</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L183" target="_blank" rel="noopener noreferrer">line 183</a></p><h5 id="parameters-1" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th>Description</th></tr></thead><tbody><tr><td><code>parameters</code></td><td>object</td><td></td><td>Parameters<br><em>Properties:</em><table class="props"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th>Default</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>includeRootProject</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>true</code></td><td class="description last">Whether to include the root project</td></tr><tr><td class="name"><code>includedDependencies</code></td><td class="type">Array&lt;(string | RegExp)&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of dependencies to include</td></tr><tr><td class="name"><code>excludedDependencies</code></td><td class="type">Array&lt;(string | RegExp)&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of dependencies to exclude</td></tr><tr><td class="name"><code>signal</code></td><td class="type">AbortSignal</td><td class="attributes">optional</td><td class="default"></td><td class="description last">Signal to abort the build</td></tr></tbody></table></td></tr><tr><td><code>projectBuiltCallback</code></td><td>function</td><td>optional</td><td>Callback invoked after each project is built</td></tr></tbody></table><h5 id="returns" tabindex="-1">Returns: <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns:&quot;">​</a></h5><p>Promise resolving with array of processed project names</p><p><strong>Type:</strong> Promise&lt;Array&lt;string&gt;&gt;</p><h4 id="async-buildtotarget-parameters-rarr-promise" tabindex="-1"><div class="jsdoc-object" id="buildToTarget"><span class="type-signature">(async) </span>buildToTarget<span class="signature">(parameters)</span><span class="type-signature"> → {Promise}</span></div> <a class="header-anchor" href="#async-buildtotarget-parameters-rarr-promise" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;buildToTarget&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;(async) &lt;/span&gt;buildToTarget&lt;span class=&quot;signature&quot;&gt;(parameters)&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt; &amp;rarr; {Promise}&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Executes a project build, including all necessary or requested dependencies, and writes the result to the given target directory.</p><p>Closes the build cache database before returning, so #closeCacheManager does not need to be called by the consumer. After this method returns, the builder must not be used for further builds. For repeated builds against the same builder instance — e.g. in a long-running BuildServer — use #build instead and close the CacheManager explicitly when done.</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L254" target="_blank" rel="noopener noreferrer">line 254</a></p><h5 id="parameters-2" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>parameters</code></td><td>object</td><td>Parameters<br><em>Properties:</em><table class="props"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th>Default</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>destPath</code></td><td class="type">string</td><td class="attributes"></td><td class="default"></td><td class="description last">Target path</td></tr><tr><td class="name"><code>cleanDest</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>false</code></td><td class="description last">Decides whether project should clean the target path before build</td></tr><tr><td class="name"><code>includedDependencies</code></td><td class="type">Array&lt;(string | RegExp)&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of names of projects to include in the build result<br> If the wildcard &#39;*&#39; is provided, all dependencies will be included in the build result.</td></tr><tr><td class="name"><code>excludedDependencies</code></td><td class="type">Array&lt;(string | RegExp)&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of names of projects to exclude from the build result.</td></tr><tr><td class="name"><code>dependencyIncludes</code></td><td class="type"><a href="@ui5_project_build_ProjectBuilder#~DependencyIncludes">@ui5/project/build/ProjectBuilder~DependencyIncludes</a></td><td class="attributes">optional</td><td class="default"></td><td class="description last">Alternative to the <code>includedDependencies</code> and <code>excludedDependencies</code> parameters.<br> Allows for a more sophisticated configuration for defining which dependencies should be<br> part of the build result. If this is provided, the other mentioned parameters are ignored.</td></tr></tbody></table></td></tr></tbody></table><h5 id="returns-1" tabindex="-1">Returns: <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns:&quot;">​</a></h5><p>Promise resolving once the build has finished</p><p><strong>Type:</strong> Promise</p><h4 id="closecachemanager" tabindex="-1"><div class="jsdoc-object" id="closeCacheManager"><span class="type-signature"></span>closeCacheManager<span class="signature">()</span><span class="type-signature"></span></div> <a class="header-anchor" href="#closecachemanager" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;closeCacheManager&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;&lt;/span&gt;closeCacheManager&lt;span class=&quot;signature&quot;&gt;()&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt;&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Releases the build cache database connection and any underlying storage resources.</p><p>Must be called by consumers of #build once they are done with this builder (e.g. when shutting down a long-running BuildServer). #buildToTarget closes the CacheManager automatically and does not require this call.</p><p>Safe to call multiple times; subsequent calls are no-ops. After this method returns, the builder must not be used for further builds.</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L157" target="_blank" rel="noopener noreferrer">line 157</a></p><h4 id="resourceschanged-changes-rarr-set-lt-string" tabindex="-1"><div class="jsdoc-object" id="resourcesChanged"><span class="type-signature"></span>resourcesChanged<span class="signature">(changes)</span><span class="type-signature"> → {Set&lt;string&gt;}</span></div> <a class="header-anchor" href="#resourceschanged-changes-rarr-set-lt-string" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;resourcesChanged&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;&lt;/span&gt;resourcesChanged&lt;span class=&quot;signature&quot;&gt;(changes)&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt; &amp;rarr; {Set&amp;lt;string&gt;}&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Propagate resource changes through the build context</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L138" target="_blank" rel="noopener noreferrer">line 138</a></p><h5 id="parameters-3" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>changes</code></td><td>Array</td><td>Array of resource changes to propagate</td></tr></tbody></table><h5 id="throws" tabindex="-1">Throws: <a class="header-anchor" href="#throws" aria-label="Permalink to &quot;Throws:&quot;">​</a></h5><p>If a build is currently running</p><p><strong>Type:</strong> Error</p><h5 id="returns-2" tabindex="-1">Returns: <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns:&quot;">​</a></h5><p>Names of projects potentially affected by the resource changes</p><p><strong>Type:</strong> Set&lt;string&gt;</p><h4 id="async-validatecaches-parameters-projectvalidatedcallbackopt-rarr-promise-lt-array-lt-string" tabindex="-1"><div class="jsdoc-object" id="validateCaches"><span class="type-signature">(async) </span>validateCaches<span class="signature">(parameters, projectValidatedCallback<span class="signature-attributes">opt</span>)</span><span class="type-signature"> → {Promise&lt;Array&lt;string&gt;&gt;}</span></div> <a class="header-anchor" href="#async-validatecaches-parameters-projectvalidatedcallbackopt-rarr-promise-lt-array-lt-string" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;validateCaches&#39;&gt;&lt;span class=&quot;type-signature&quot;&gt;(async) &lt;/span&gt;validateCaches&lt;span class=&quot;signature&quot;&gt;(parameters, projectValidatedCallback&lt;span class=&quot;signature-attributes&quot;&gt;opt&lt;/span&gt;)&lt;/span&gt;&lt;span class=&quot;type-signature&quot;&gt; &amp;rarr; {Promise&amp;lt;Array&amp;lt;string&gt;&gt;}&lt;/span&gt;&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Validate the build cache for a set of projects without actually building any of them.</p><p>Intended to be used by long-running consumers (such as the BuildServer) to proactively determine whether a cached build result can be reused for a project. Walks the dependency graph in the same order as #build, so dependencies are validated before their dependents and resource changes propagate correctly.</p><p>For each requested project, the given callback is invoked with the validation result once that project has been validated. The result indicates whether a cached build result is available and can be used (<code>true</code>) or whether a build would be required (<code>false</code>).</p><p>Like #build, this method is mutually exclusive with itself and with other build operations on the same builder instance. Source change propagation via #resourcesChanged is blocked while validation is running.</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L225" target="_blank" rel="noopener noreferrer">line 225</a></p><h5 id="parameters-4" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th>Description</th></tr></thead><tbody><tr><td><code>parameters</code></td><td>object</td><td></td><td>Parameters<br><em>Properties:</em><table class="props"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>projects</code></td><td class="type">Array&lt;string&gt;</td><td class="attributes"></td><td class="description last">Names of projects to validate</td></tr><tr><td class="name"><code>signal</code></td><td class="type">AbortSignal</td><td class="attributes">optional</td><td class="description last">Signal to abort the validation</td></tr><tr><td class="name"><code>willValidate</code></td><td class="type">function</td><td class="attributes">optional</td><td class="description last">Hook invoked synchronously just before each project&#39;s <code>validateCache</code><br> call. Receives <code>(projectName)</code>. Return value is ignored. Use this to<br> claim the project state in the caller (e.g. transition to a &quot;validating&quot;<br> lifecycle state).</td></tr></tbody></table></td></tr><tr><td><code>projectValidatedCallback</code></td><td>function</td><td>optional</td><td>Callback invoked after each requested project has been validated.<br> Receives <code>(projectName, project, projectBuildContext, usesCache)</code>.</td></tr></tbody></table><h5 id="returns-3" tabindex="-1">Returns: <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns:&quot;">​</a></h5><p>Promise resolving with the names of all processed projects</p><p><strong>Type:</strong> Promise&lt;Array&lt;string&gt;&gt;</p><h3 id="type-definitions" tabindex="-1">Type Definitions <a class="header-anchor" href="#type-definitions" aria-label="Permalink to &quot;Type Definitions&quot;">​</a></h3><h4 id="buildconfiguration" tabindex="-1"><div class="jsdoc-object" id="~BuildConfiguration">BuildConfiguration</div> <a class="header-anchor" href="#buildconfiguration" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;~BuildConfiguration&#39;&gt;BuildConfiguration&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> Build Configuration</p><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L19" target="_blank" rel="noopener noreferrer">line 19</a></p><h5 id="properties" tabindex="-1">Properties: <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties:&quot;">​</a></h5><table class="props"><thead><tr><th>Name</th><th>Type</th><th>Attributes</th><th>Default</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>selfContained</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>false</code></td><td class="description last">Flag to activate self contained build</td></tr><tr><td class="name"><code>cssVariables</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>false</code></td><td class="description last">Flag to activate CSS variables generation</td></tr><tr><td class="name"><code>jsdoc</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>false</code></td><td class="description last">Flag to activate JSDoc build</td></tr><tr><td class="name"><code>createBuildManifest</code></td><td class="type">boolean</td><td class="attributes">optional</td><td class="default"><code>false</code></td><td class="description last">Whether to create a build manifest file for the root project.<br> This is currently only supported for projects of type &#39;library&#39; and &#39;theme-library&#39;<br> No other dependencies can be included in the build result.</td></tr><tr><td class="name"><code>outputStyle</code></td><td class="type"><a href="module-@ui5_project_build_ProjectBuilderOutputStyle">module:@ui5/project/build/ProjectBuilderOutputStyle</a></td><td class="attributes">optional</td><td class="default"><code>Default</code></td><td class="description last">Processes build results into a specific directory structure.</td></tr><tr><td class="name"><code>includedTasks</code></td><td class="type">Array&lt;string&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of tasks to be included</td></tr><tr><td class="name"><code>excludedTasks</code></td><td class="type">Array&lt;string&gt;</td><td class="attributes">optional</td><td class="default"><code>[]</code></td><td class="description last">List of tasks to be excluded.<br> If the wildcard &#39;*&#39; is provided, only the included tasks will be executed.</td></tr><tr><td class="name"><code>cache</code></td><td class="type"><a href="module-@ui5_project_build_cache_Cache">module:@ui5/project/build/cache/Cache</a></td><td class="attributes">optional</td><td class="default"><code>Cache.Default</code></td><td class="description last">Cache mode to use for building UI5 projects</td></tr></tbody></table><p>Build Configuration</p><h5 id="type" tabindex="-1">Type: <a class="header-anchor" href="#type" aria-label="Permalink to &quot;Type:&quot;">​</a></h5><ul><li>object</li></ul><h4 id="dependencyincludes" tabindex="-1"><div class="jsdoc-object" id="~DependencyIncludes">DependencyIncludes</div> <a class="header-anchor" href="#dependencyincludes" aria-label="Permalink to &quot;&lt;div class=&#39;jsdoc-object&#39; id=&#39;~DependencyIncludes&#39;&gt;DependencyIncludes&lt;/div&gt;&quot;">​</a></h4><p><strong>Description:</strong> As an alternative to providing plain lists of names of dependencies to include and exclude, you can provide a more complex &quot;Dependency Includes&quot; object to define which dependencies should be part of the build result. <br> This information is then used to compile lists of <code>includedDependencies</code> and <code>excludedDependencies</code>, which are applied during the build process. <br><br> Regular expression-parameters are directly applied to a list of all project dependencies so that they don&#39;t need to be evaluated in later processing steps. <br><br> Generally, includes are handled with a higher priority than excludes. Additionally, operations for processing transitive dependencies are handled with a lower priority than explicitly mentioned dependencies. The &quot;default&quot; dependency-includes are appended at the end. <br><br> The priority of the various dependency lists is applied in the following order. Note that a later exclude can&#39;t overrule an earlier include. <br></p><ol><li><code>includeDependency</code>, <code>includeDependencyRegExp</code></li><li><code>excludeDependency</code>, <code>excludeDependencyRegExp</code></li><li><code>includeDependencyTree</code></li><li><code>excludeDependencyTree</code></li><li><code>defaultIncludeDependency</code>, <code>defaultIncludeDependencyRegExp</code>, <code>defaultIncludeDependencyTree</code></li></ol><p><strong>Source:</strong> <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js" target="_blank" rel="noopener noreferrer">project/lib/build/ProjectBuilder.js</a>, <a href="https://github.com/UI5/cli/blob/main/packages//project/lib/build/ProjectBuilder.js#L40" target="_blank" rel="noopener noreferrer">line 40</a></p><h5 id="properties-1" tabindex="-1">Properties: <a class="header-anchor" href="#properties-1" aria-label="Permalink to &quot;Properties:&quot;">​</a></h5><table class="props"><thead><tr><th>Name</th><th>Type</th><th class="last">Description</th></tr></thead><tbody><tr><td class="name"><code>includeAllDependencies</code></td><td class="type">boolean</td><td class="description last">Whether all dependencies should be part of the build result<br> This parameter has the lowest priority and basically includes all remaining (not excluded) projects as include</td></tr><tr><td class="name"><code>includeDependency</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">The dependencies to be considered in <code>includedDependencies</code>; the<br> <code>*</code> character can be used as wildcard for all dependencies and<br> is an alias for the CLI option <code>--all</code></td></tr><tr><td class="name"><code>includeDependencyRegExp</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">Strings which are interpreted as regular expressions<br> to describe the selection of dependencies to be considered in <code>includedDependencies</code></td></tr><tr><td class="name"><code>includeDependencyTree</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">The dependencies to be considered in <code>includedDependencies</code>;<br> transitive dependencies are also appended</td></tr><tr><td class="name"><code>excludeDependency</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">The dependencies to be considered in <code>excludedDependencies</code></td></tr><tr><td class="name"><code>excludeDependencyRegExp</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">Strings which are interpreted as regular expressions<br> to describe the selection of dependencies to be considered in <code>excludedDependencies</code></td></tr><tr><td class="name"><code>excludeDependencyTree</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">The dependencies to be considered in <code>excludedDependencies</code>;<br> transitive dependencies are also appended</td></tr><tr><td class="name"><code>defaultIncludeDependency</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">Same as <code>includeDependency</code> parameter;<br> typically used in project build settings</td></tr><tr><td class="name"><code>defaultIncludeDependencyRegExp</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">Same as <code>includeDependencyRegExp</code> parameter;<br> typically used in project build settings</td></tr><tr><td class="name"><code>defaultIncludeDependencyTree</code></td><td class="type">Array&lt;string&gt;</td><td class="description last">Same as <code>includeDependencyTree</code> parameter;<br> typically used in project build settings</td></tr></tbody></table><p>As an alternative to providing plain lists of names of dependencies to include and exclude, you can provide a more complex &quot;Dependency Includes&quot; object to define which dependencies should be part of the build result. <br> This information is then used to compile lists of <code>includedDependencies</code> and <code>excludedDependencies</code>, which are applied during the build process. <br><br> Regular expression-parameters are directly applied to a list of all project dependencies so that they don&#39;t need to be evaluated in later processing steps. <br><br> Generally, includes are handled with a higher priority than excludes. Additionally, operations for processing transitive dependencies are handled with a lower priority than explicitly mentioned dependencies. The &quot;default&quot; dependency-includes are appended at the end. <br><br> The priority of the various dependency lists is applied in the following order. Note that a later exclude can&#39;t overrule an earlier include. <br></p><ol><li><code>includeDependency</code>, <code>includeDependencyRegExp</code></li><li><code>excludeDependency</code>, <code>excludeDependencyRegExp</code></li><li><code>includeDependencyTree</code></li><li><code>excludeDependencyTree</code></li><li><code>defaultIncludeDependency</code>, <code>defaultIncludeDependencyRegExp</code>, <code>defaultIncludeDependencyTree</code></li></ol><h5 id="type-1" tabindex="-1">Type: <a class="header-anchor" href="#type-1" aria-label="Permalink to &quot;Type:&quot;">​</a></h5><ul><li>object</li></ul>',73)])])}const b=t(d,[["render",o]]);export{h as __pageData,b as default};
